import React, { useRef, useImperativeHandle, useState } from "react";
import { cn, cva } from "../../lib/utils";
import { PersonPlaceholderIcon } from "../../icons/PersonPlaceholder";
import {
  AvatarProps,
  AvatarShape,
  AvatarSize,
  AvatarColorScheme,
} from "../../types/avatar";
import "./avatar.css";

/**
 * Avatar size variants
 */
const avatarVariants = cva(
  [
    "inline-flex items-center justify-center",
    "font-medium overflow-hidden",
    "select-none",
  ],
  {
    variants: {
      shape: {
        [AvatarShape.Circle]: "rounded-full",
        [AvatarShape.Square]: "",
      },
      size: {
        [AvatarSize.XS]: "h-[2rem] w-[2rem] text-[1rem]",
        [AvatarSize.S]: "h-[3rem] w-[3rem] text-[1.125rem]",
        [AvatarSize.M]: "h-[4rem] w-[4rem] text-[1.5rem]",
        [AvatarSize.L]: "h-[5rem] w-[5rem] text-[2.25rem]",
        [AvatarSize.XL]: "h-[7rem] w-[7rem] text-[3rem]",
      },
      colorScheme: {
        [AvatarColorScheme.Accent1]: "bg-[var(--avatar-accent-bg-1)] text-[var(--avatar-accent-color-1)]",
        [AvatarColorScheme.Accent2]: "bg-[var(--avatar-accent-bg-2)] text-[var(--avatar-accent-color-2)]",
        [AvatarColorScheme.Accent3]: "bg-[var(--avatar-accent-bg-3)] text-[var(--avatar-accent-color-3)]",
        [AvatarColorScheme.Accent4]: "bg-[var(--avatar-accent-bg-4)] text-[var(--avatar-accent-color-4)]",
        [AvatarColorScheme.Accent5]: "bg-[var(--avatar-accent-bg-5)] text-[var(--avatar-accent-color-5)]",
        [AvatarColorScheme.Accent6]: "bg-[var(--avatar-accent-bg-6)] text-[var(--avatar-accent-color-6)]",
        [AvatarColorScheme.Accent7]: "bg-[var(--avatar-accent-bg-7)] text-[var(--avatar-accent-color-7)]",
        [AvatarColorScheme.Accent8]: "bg-[var(--avatar-accent-bg-8)] text-[var(--avatar-accent-color-8)]",
        [AvatarColorScheme.Accent9]: "bg-[var(--avatar-accent-bg-9)] text-[var(--avatar-accent-color-9)]",
        [AvatarColorScheme.Accent10]: "bg-[var(--avatar-accent-bg-10)] text-[var(--avatar-accent-color-10)]",
        [AvatarColorScheme.Placeholder]: "bg-muted text-sapphire-text-tertiary",
      },
      interactive: {
        true: "cursor-pointer hover:opacity-80 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
        false: "",
      },
      disabled: {
        true: "opacity-50 cursor-not-allowed",
        false: "",
      },
    },
    compoundVariants: [
      {
        shape: AvatarShape.Square,
        size: AvatarSize.XS,
        className: "rounded-sapphire-s",    // 4px — Figma token --radius-s
      },
      {
        shape: AvatarShape.Square,
        size: AvatarSize.S,
        className: "rounded-[6px]",          // 6px — hardcoded in Figma
      },
      {
        shape: AvatarShape.Square,
        size: AvatarSize.M,
        className: "rounded-sapphire-m",    // 8px — Figma token --radius-m
      },
      {
        shape: AvatarShape.Square,
        size: AvatarSize.L,
        className: "rounded-[12px]",         // 12px — hardcoded in Figma
      },
      {
        shape: AvatarShape.Square,
        size: AvatarSize.XL,
        className: "rounded-sapphire-l",    // 16px — Figma token --radius-l
      },
      // Neutralize interactive hover/focus/cursor when disabled
      {
        interactive: true,
        disabled: true,
        className: "cursor-not-allowed hover:opacity-50 focus:ring-0 focus:ring-offset-0",
      },
    ],
    defaultVariants: {
      shape: AvatarShape.Circle,
      size: AvatarSize.M,
      colorScheme: AvatarColorScheme.Accent6,
      interactive: false,
      disabled: false,
    },
  }
);

/**
 * Icon size mapping
 */
const iconSizeMap: Record<AvatarSize | string, string> = {
  [AvatarSize.XS]: "h-[1rem] w-[1rem]",
  [AvatarSize.S]: "h-[1.125rem] w-[1.125rem]",
  [AvatarSize.M]: "h-[1.5rem] w-[1.5rem]",
  [AvatarSize.L]: "h-[2.25rem] w-[2.25rem]",
  [AvatarSize.XL]: "h-[3rem] w-[3rem]",
};

/**
 * Avatar component
 *
 * Displays user avatars with support for images, initials, icons, and badges.
 *
 * @example
 * ```tsx
 * // With image
 * <Avatar image="/user.jpg" />
 *
 * // With initials
 * <Avatar initials="JD" colorScheme="Accent1" />
 *
 * // With icon
 * <Avatar icon={<PersonPlaceholderIcon />} />
 *
 * // Interactive with badge
 * <Avatar image="/user.jpg" interactive badge={<span className="bg-green-500 h-2 w-2 rounded-full" />} />
 * ```
 */
export function Avatar({
  shape = AvatarShape.Circle,
  size = AvatarSize.M,
  colorScheme = AvatarColorScheme.Accent6,
  icon,
  image,
  fallbackImage,
  initials,
  interactive = false,
  disabled = false,
  accessibleName = "Avatar",
  badge,
  onClick,
  className,
  style,
  ref,
}: AvatarProps) {
    const avatarRef = useRef<HTMLDivElement>(null);
    const [imageError, setImageError] = useState(false);
    const [fallbackError, setFallbackError] = useState(false);

    useImperativeHandle(ref, () => ({
      focus: () => avatarRef.current?.focus(),
      isFocused: () => document.activeElement === avatarRef.current,
      get nativeElement() { return avatarRef.current; },
      getNativeElement: () => avatarRef.current,
    }));

    const handleImageError = () => {
      if (!imageError) {
        setImageError(true);
      } else if (fallbackImage && !fallbackError) {
        setFallbackError(true);
      }
    };

    const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
      if (!disabled && interactive && onClick) {
        onClick(e);
      }
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
      if (!disabled && interactive && (e.key === "Enter" || e.key === " ")) {
        e.preventDefault();
        onClick?.(e as unknown as React.MouseEvent<HTMLDivElement>);
      }
    };

    // Determine what to display
    const showImage = image && !imageError;
    const showFallbackImage = !showImage && fallbackImage && !fallbackError;
    const showInitials = !showImage && !showFallbackImage && initials;
    const showIcon = !showImage && !showFallbackImage && !showInitials;

    const iconSize = iconSizeMap[size as string] || iconSizeMap[AvatarSize.M];

    return (
      <div className="relative inline-block">
        <div
          ref={avatarRef}
          role={interactive ? "button" : "img"}
          tabIndex={interactive && !disabled ? 0 : undefined}
          aria-label={showInitials ? `${accessibleName} ${initials}` : accessibleName}
          aria-disabled={disabled}
          onClick={handleClick}
          onKeyDown={handleKeyDown}
          className={cn(
            avatarVariants({
              shape: shape as AvatarShape,
              size: size as AvatarSize,
              colorScheme: colorScheme as AvatarColorScheme,
              interactive,
              disabled,
            }),
            className
          )}
          style={style}
        >
          {showImage && (
            <img
              src={image}
              alt={accessibleName || ""}
              className="h-full w-full object-cover"
              onError={handleImageError}
            />
          )}
          {showFallbackImage && (
            <img
              src={fallbackImage}
              alt={accessibleName || ""}
              className="h-full w-full object-cover"
              onError={handleImageError}
            />
          )}
          {showInitials && (
            <span className="uppercase">
              {initials.slice(0, 3)}
            </span>
          )}
          {showIcon && (
            icon ? (
              <span className={cn(iconSize, "flex items-center justify-center")}>{icon}</span>
            ) : (
              <PersonPlaceholderIcon className={iconSize} />
            )
          )}
        </div>
        {badge && (
          <div className="absolute top-0 right-0">
            {badge}
          </div>
        )}
      </div>
    );
}
